const IMAGE_FIXTURES = {
  'image/jpeg': {
    name: 'test.jpg',
    base64:
      '',
  },
  'image/png': {
    name: 'test.png',
    base64:
      'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAAAXNSR0IArs4c6QAAAERlWElmTU0AKgAAAAgAAYdpAAQAAAABAAAAGgAAAAAAA6ABAAMAAAABAAEAAKACAAQAAAABAAAAAaADAAQAAAABAAAAAQAAAAD5Ip3+AAAADUlEQVQIHWP4vWuXMwAH1gKzqEgayAAAAABJRU5ErkJggg==',
  },
  'image/gif': {
    name: 'test.gif',
    base64:
      'R0lGODdhAQABAJEAAAAAAPu6uv///wAAACH5BAkAAAMALAAAAAABAAEAAAICTAEAOw==',
  },
  'image/webp': {
    name: 'test.webp',
    base64:
      'UklGRiIAAABXRUJQVlA4IBYAAAAwAQCdASoBAAEAAUAmJaACdAD0AAD+JaQAA3AA/vuUAAA=',
  },
} as const

function decodeBase64(base64: string): Uint8Array {
  if (typeof atob === 'function') {
    return Uint8Array.from(atob(base64), (char) => char.charCodeAt(0))
  }

  return Uint8Array.from(Buffer.from(base64, 'base64'))
}

export function createFixtureImageFile(
  type: keyof typeof IMAGE_FIXTURES = 'image/jpeg',
): File {
  const fixture = IMAGE_FIXTURES[type]
  return new File([decodeBase64(fixture.base64)], fixture.name, { type })
}
